// Obtener todos los tweets de Hoja 1
const allTweets = $('Leer Tweets').all().map(i => i.json);

// Obtener textos ya procesados del Log
let processedTexts = new Set();
try {
  const logRows = $('Leer Log Procesados').all();
  logRows.forEach(row => {
    const texto = row.json['texto '] ?? row.json['texto'] ?? '';
    if (texto) processedTexts.add(texto.trim());
  });
} catch(e) {
  // Log vacío, procesar todo
}

// Filtrar solo los tweets que NO están en el log
const unprocessed = allTweets.filter(row => {
  const tweet = (row.tweet ?? '').trim();
  return tweet !== '' && !processedTexts.has(tweet);
});

if (unprocessed.length === 0) {
  return [];
}

return unprocessed.map(row => ({ json: row }));

const raw = $input.first().json.text ?? '';

let parsed;
try {
  const cleaned = raw.trim().replace(/^```json\n?/, '').replace(/\n?```$/, '');
  parsed = JSON.parse(cleaned);
} catch(e) {
  const upper = raw.toUpperCase();
  let sentiment = 'NEUTRAL';
  if (upper.includes('NEGATIVO')) sentiment = 'NEGATIVO';
  else if (upper.includes('POSITIVO')) sentiment = 'POSITIVO';
  parsed = { sentiment, score: 0.5, parse_error: true };
}

const valid = ['POSITIVO', 'NEGATIVO', 'NEUTRAL'];
if (!valid.includes(parsed.sentiment)) {
  parsed.sentiment = 'NEUTRAL';
  parsed.parse_error = true;
}

return [{
  json: {
    ...($input.first().json),
    sentiment: parsed.sentiment,
    sentiment_score: parsed.score ?? 0.5,
    parse_error: parsed.parse_error ?? false,
    raw_llm_response: raw
  }
}];

