const raw = $input.first().json.llm_text ?? '';
const inputData = $input.first().json;
const tweet_text = inputData.tweet_text ?? inputData.tweet ?? 'No disponible';
const tweet_author = inputData.tweet_author ?? inputData.author ?? 'No disponible';
const tweet_date = inputData.tweet_date ?? inputData.date ?? 'No disponible';
const sentiment_score = inputData.sentiment_score ?? 0;

let analysis;
try {
  const cleaned = raw.trim().replace(/^```json\n?/, '').replace(/\n?```$/, '');
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = {
    draft: 'No se pudo generar el borrador. Revisar manualmente.',
    tone: 'AGRADECIDO',
    parse_error: true
  };
}

const toneEmoji = { 'ENTUSIASTA': '🎉', 'AGRADECIDO': '🙏', 'CERCANO': '😊' }[analysis.tone] ?? '✨';
const score = (sentiment_score * 100).toFixed(0);

const emailHtml = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="font-family: Arial, sans-serif; background: #f3f4f6; padding: 20px; margin: 0;">
  <div style="max-width: 600px; margin: 0 auto; background: white; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.1);">
    <div style="background: #16A34A; padding: 20px 24px;">
      <h1 style="color: white; margin: 0; font-size: 20px;">💚 Tweet Positivo Detectado</h1>
      <p style="color: #BBF7D0; margin: 4px 0 0 0; font-size: 13px;">Oportunidad de engagement para community management</p>
    </div>
    <div style="padding: 20px 24px; border-bottom: 1px solid #E5E7EB;">
      <table style="width: 100%; border-collapse: collapse;">
        <tr>
          <td style="padding: 6px 0; color: #6B7280; font-size: 13px; width: 120px;"><b>Autor</b></td>
          <td style="padding: 6px 0; font-size: 13px; color: #111827;">${tweet_author}</td>
        </tr>
        <tr>
          <td style="padding: 6px 0; color: #6B7280; font-size: 13px;"><b>Fecha</b></td>
          <td style="padding: 6px 0; font-size: 13px; color: #111827;">${tweet_date}</td>
        </tr>
        <tr>
          <td style="padding: 6px 0; color: #6B7280; font-size: 13px;"><b>Confianza</b></td>
          <td style="padding: 6px 0; font-size: 13px; color: #111827;">${score}%</td>
        </tr>
        <tr>
          <td style="padding: 6px 0; color: #6B7280; font-size: 13px;"><b>Tono</b></td>
          <td style="padding: 6px 0;">
            <span style="background: #16A34A; color: white; padding: 2px 10px; border-radius: 12px; font-size: 12px; font-weight: bold;">${toneEmoji} ${analysis.tone}</span>
          </td>
        </tr>
      </table>
    </div>
    <div style="padding: 16px 24px; background: #F0FDF4; border-left: 4px solid #16A34A; margin: 20px 24px; border-radius: 4px;">
      <p style="margin: 0; font-size: 13px; color: #374151; font-style: italic;">"${tweet_text}"</p>
    </div>
    <div style="padding: 0 24px 20px;">
      <h3 style="color: #111827; font-size: 14px; margin-bottom: 8px;">✏️ Borrador de respuesta sugerida</h3>
      <div style="background: #F9FAFB; border: 1px dashed #16A34A; border-radius: 6px; padding: 14px;">
        <p style="color: #111827; font-size: 14px; margin: 0; line-height: 1.6;">${analysis.draft}</p>
      </div>
      <p style="color: #9CA3AF; font-size: 11px; margin: 8px 0 0 0;">Podés copiar y pegar este texto directamente en Twitter/X</p>
    </div>
    <div style="background: #F9FAFB; padding: 12px 24px; text-align: center;">
      <p style="color: #9CA3AF; font-size: 11px; margin: 0;">Generado automáticamente por el sistema de monitoreo n8n</p>
    </div>
  </div>
</body>
</html>`;

return [{
  json: {
    tweet_text,
    tweet_author,
    tweet_date,
    sentiment_score,
    positive_draft: analysis.draft,
    positive_tone: analysis.tone,
    action_taken: 'email_borrador_enviado',
    email_html: emailHtml,
    email_subject: `[POSITIVO] Nuevo tweet de ${tweet_author} - Borrador listo`
  }
}];
